@function sin($angle)
  $sin: 0
  // angle -> radians
  $rad: math.div($angle, 180) * $PI
  // interval determines precision
  @for $i from 0 through 25
    $sin: $sin + math.div(pow(-1, $i) * pow($rad, (2 * $i + 1)), fact(2 * $i + 1))
  @return $sin

@function str-replace($string, $search, $replace: '')
  $index: string.index($string, $search)

  @if $index
    $start: string.slice($string, 1, $index - 1)
    $end: str-replace(string.slice($string, $index + string.length($search)), $search, $replace)
    @return $start + $replace + $end

  @return $string

@use 'sass:map'
@use '../settings'

@mixin elevation($z)
  &
    box-shadow: map.get(settings.$shadow-key, $z), map.get(settings.$shadow-ambient, $z)
    --v-elevation-overlay: color-mix(in srgb, var(--v-elevation-overlay-color) #{$z * settings.$elevation-overlay-step}, transparent)

@mixin elevationTransition($duration: 280ms, $easing: cubic-bezier(0.4, 0, 0.2, 1))
  &
    transition: $duration $easing
    transition-property: box-shadow, --v-elevation-overlay

@function dip($number, $em-offset, $dip-conversion)
  $unitless-em-offset: $em-offset / 1em
  @if unitless($em-offset)
    $unitless-em-offset: $em-offset
  @if $dip-conversion == px
    @return $number * 1px
  @if $dip-conversion == em
    @return ($number / ($base-size / 1px)) * (1 / $unitless-em-offset) * 1em
  @if $dip-conversion == rem
    @return $number / ($base-size / 1px) * 1rem

=z-position($z-index: 0, $shadow: false, $text: false)
  z-index: $z-index * 100
  @if $shadow == true
    box-shadow: $x-light $y-light ($z-index * 2) $z-lighting-color
  @if $shadow == false
    box-shadow: 0 0 0 transparent
  @if $text == true
    text-shadow: 45px 45px 0 $z-lighting-color
    box-shadow: 0 0 0 transparent
  @if $z-index > 10
    @error "oops the $z-index value for the mixin z-position was set to #{$z-index}, keep the value between 0 and 10."

@function findDarkColor($color)
  @if type-of($color) == 'color'
    $base-l: 29%
    $luminance: colorLuminance($color)
    $luminance-delta: (0.53 - $luminance)
    $target-l: round($base-l + ($luminance-delta * 53))
    @return change-color($color, $lightness: max($base-l, $target-l))
  @return $text-strong

@function change($number, $units)

	@if meta.type-of($number) != 'number'
		@error parameter-type.parameter-type('change', 'number', $number, 'number')

	@if meta.type-of($units) != 'number'
		@error parameter-type.parameter-type('change', 'units', $units, 'number')

	$units: math.abs($units)

	@return unitless.unitless($number) * ($units - $units + 1)

@function fact($number)

	@if meta.type-of($number) != 'number' or $number != math.floor($number)
		@error parameter-type.parameter-type('fact', 'number', $number, 'integer')

	$number: math.abs($number)

	$result: 1

	@while $number > 0
		$result: $result * $number
		$number: $number - 1

	@return $result

@function get-keyword($args, $name, $default: null)

	@if meta.type-of($args) != 'arglist'
		@error parameter-type.parameter-type('get-keyword', 'args', $args, 'arglist')

	@if meta.type-of($name) != 'string'
		@error parameter-type.parameter-type('get-keyword', 'name', $name, 'string')

	$args: meta.keywords($args)

	@return if(sass(map.has-key($args, $name)): map.get($args, $name); else: $default)

@function call-or-reference($function, $args...)

	@if meta.type-of($function) != 'function'
		@error parameter-type.parameter-type('call-or-reference', 'function', $function, 'function')

	@if list.length($args) != 0 or list.length(meta.keywords($args)) != 0
		@return meta.call($function, $args...)

	@return $function

@function contrast($first-color, $second-color)

	@if meta.type-of($first-color) != 'color'
		@error parameter-type.parameter-type('contrast', 'first-color', $first-color, 'color')

	@if meta.type-of($second-color) != 'color'
		@error parameter-type.parameter-type('contrast', 'second-color', $second-color, 'color')

	$first-color: luminance.luminance($first-color) + 0.05
	$second-color: luminance.luminance($second-color) + 0.05

	@return math.div(math.max($first-color, $second-color), math.min($first-color, $second-color))

@function data($data, $media-type: 'text/plain', $encode: true)

	@if meta.type-of($data) != 'string'
		@error parameter-type.parameter-type('data', 'data', $data, 'string')

	@if meta.type-of($media-type) != 'string'
		@error parameter-type.parameter-type('data', 'media-type', $media-type, 'string')

	@if meta.type-of($encode) != 'bool'
		@error parameter-type.parameter-type('data', 'encode', $encode, 'boolean')

	@if $encode
		$data: encode.encode($data)

	@return url('data:#{$media-type},#{$data}')

@function find($list, $predicate, $args...)

	@if meta.type-of($predicate) != 'function'
		@error parameter-type.parameter-type('find', 'predicate', $predicate, 'function')

	$index: 1

	@each $item in $list

		@if meta.call($predicate, $item, $index, $list, $args...)
			@return $item

		$index: $index + 1

	@return null

@function includes($string, $substring, $start-at: 1)

	@if meta.type-of($string) != 'string'
		@error parameter-type.parameter-type('includes', 'string', $string, 'string')

	@if meta.type-of($substring) != 'string'
		@error parameter-type.parameter-type('includes', 'substring', $substring, 'string')

	$start-at: validate-index.validate-index('includes', 'start-at', $start-at, $string)

	@if meta.type-of($start-at) != 'number'
		@error $start-at

	@return index.index($string, $substring, $start-at) != 0

@function str-fr($selector, $name, $i: '')
  @return str-replace(str-replace($selector, '<name>', $name), '<i>', $i)

@function str-fe($selector, $name, $noProc, $i: '')
  @if $noProc
    @return str-fr($selector, $name, $i)
  @return list.join(str-fr($selector, '', $i), str-fr($selector, $name, $i), $separator: comma)

=grid($units, $grid-override: false)
  // Add padding to items on the grid.
  width: grid($units, $grid-mixin-counter + 1)
  @extend #{$object-type}column
  @if $grid-mixin-counter >= $columns
    $grid-mixin-counter: 0
  @if $grid-mixin-counter != 0
    @extend #{$object-type}next-column
  $grid-mixin-counter: $grid-mixin-counter + $units

@function is-dark($color)

	@if meta.type-of($color) != 'color'
		@error parameter-type.parameter-type('is-dark', 'color', $color, 'color')

	@return math.div(color.channel($color, 'red', $space: rgb) * 299 + color.channel($color, 'green', $space: rgb) * 587 + color.channel($color, 'blue', $space: rgb) * 114, 1000) < 128

@function svg($data...)
	$data: join.join($data, '')
	$namespace: 'xmlns="http://www.w3.org/2000/svg"'

	@if not includes.includes($data, $namespace)
		$data: replace.replace($data, '<svg', '$& #{$namespace}')

	@return data.data($data, 'image/svg+xml')

=grid($units, $grid-override: false)
  @if $grid-mixin-counter >= $columns
    $grid-mixin-counter: 0
  @if $grid-override == false
    width: grid($units, $grid-mixin-counter)
  @if $grid-override != false
    width: grid($units, $grid-mixin-counter)
  @if $grid-mixin-counter == 0
    float: left
  @else
    @extend #{$object-type}next-column
  @warn $grid-mixin-counter
  $grid-mixin-counter: $grid-mixin-counter + $units
  @warn $grid-mixin-counter
